function readPersistedSessionUser(): SessionUser | null {
  if (typeof window === "undefined") {
    return null;
  }

  try {
    const storedValue = window.localStorage.getItem(sessionStorageKey);

    if (!storedValue) {
      return null;
    }

    const parsedValue = JSON.parse(storedValue) as Partial<SessionUser>;

    if (
      typeof parsedValue.id !== "string"
      || typeof parsedValue.name !== "string"
      || typeof parsedValue.email !== "string"
      || typeof parsedValue.role !== "string"
    ) {
      window.localStorage.removeItem(sessionStorageKey);
      return null;
    }

    return {
      id: parsedValue.id,
      name: parsedValue.name,
      email: parsedValue.email,
      role: parsedValue.role,
    };
  } catch {
    window.localStorage.removeItem(sessionStorageKey);
    return null;
  }
}

async function readPersistedImportContainerTemplates(userId: string): Promise<ImportContainerTemplateRecord[]> {
  if (typeof window === "undefined" || !userId) {
    return [];
  }

  try {
    const response = await fetch(`${apiBaseUrl}/management/import-templates?userId=${encodeURIComponent(userId)}`);

    if (!response.ok) {
      return [];
    }

    const templates = (await response.json()) as ImportContainerTemplateRecord[];
    return templates;
  } catch {
    return [];
  }
}

