function createInitialContainerImportForm(products: ProductOption[]): ContainerImportFormState {
  return {
    containerType: "seco",
    containerSize: "20ft",
    measurementUnit: "m3",
    importDate: new Date().toISOString().slice(0, 10),
    shipmentReference: "",
    expenseItems: [],
    notes: "",
    products: buildContainerImportProducts(products),
  };
}

function formatContainerType(value: ContainerType) {
  return containerTypeOptions.find((option) => option.value === value)?.label ?? value;
}

function formatContainerSize(value: string) {
  return containerSizeOptions.find((option) => option.value === value)?.label ?? value;
}

function getTemplateId(template: ImportContainerTemplateRecord): string {
  return template._id || template.id || "";
}

function getContainerCapacityCubicMeters(value: ContainerImportFormState["containerSize"]) {
  return containerCapacityBySize[value] ?? 30;
}

function getContainerCapacityKilograms(value: ContainerImportFormState["containerSize"]) {
  return containerCapacityKgBySize[value] ?? 24000;
}

function getProductExportVolumeCubicFeet(product: Pick<ProductOption, "containerType" | "exportVolumeCubicFeet"> | {
  containerType?: string;
  exportVolumeCubicFeet?: number;
}) {
  const configuredVolume = Number(product.exportVolumeCubicFeet ?? 0);

  if (product.containerType === "refrigerado") {
    return configuredVolume > 0 ? configuredVolume : defaultRefrigeratedExportVolumeCubicFeet;
  }

  return 0;
}

function getProductExportVolumeCubicMeters(product: Pick<ProductOption, "containerType" | "exportVolumeCubicFeet"> | {
  containerType?: string;
  exportVolumeCubicFeet?: number;
}) {
  const exportVolumeCubicFeet = getProductExportVolumeCubicFeet(product);
  return exportVolumeCubicFeet > 0 ? exportVolumeCubicFeet / cubicFeetPerCubicMeter : 0;
}

function calculateProductBoxVolumeCubicMeters(product: Pick<ProductOption, "boxLengthCm" | "boxWidthCm" | "boxHeightCm">) {
  const length = Number(product.boxLengthCm || 0);
  const width = Number(product.boxWidthCm || 0);
  const height = Number(product.boxHeightCm || 0);

  if (length <= 0 || width <= 0 || height <= 0) {
    return 0;
  }

  return (length * width * height) / 1_000_000;
}

function calculateEstimatedBoxes(importedQuantity: number, unitsPerBox: number) {
  if (importedQuantity <= 0 || unitsPerBox <= 0) {
    return 0;
  }

  return Math.ceil(importedQuantity / unitsPerBox);
}

function deriveImportedQuantityFromExportUnits(exportUnitCount: number, unitsPerBox: number) {
  if (exportUnitCount <= 0) {
    return 0;
  }

  return exportUnitCount * (unitsPerBox > 0 ? unitsPerBox : 1);
}

function deriveExportUnitCountFromImportedQuantity(importedQuantity: number, unitsPerBox: number) {
  if (importedQuantity <= 0) {
    return 0;
  }

  return unitsPerBox > 0 ? importedQuantity / unitsPerBox : importedQuantity;
}

function formatCubicMeters(value: number) {
  return `${new Intl.NumberFormat("es-CO", {
    minimumFractionDigits: value < 10 ? 2 : 1,
    maximumFractionDigits: value < 10 ? 2 : 1,
  }).format(Number.isFinite(value) ? value : 0)} m3`;
}

function formatCubicFeet(value: number) {
  return `${new Intl.NumberFormat("es-CO", {
    minimumFractionDigits: value < 100 ? 2 : 1,
    maximumFractionDigits: value < 100 ? 2 : 1,
  }).format(Number.isFinite(value) ? value : 0)} pie3`;
}

function formatKilograms(value: number) {
  return `${new Intl.NumberFormat("es-CO", {
    minimumFractionDigits: 0,
    maximumFractionDigits: 0,
  }).format(Number.isFinite(value) ? value : 0)} kg`;
}

function formatContainerMeasure(value: number, unit: ContainerMeasurementUnit) {
  if (unit === "kg") {
    return formatKilograms(value);
  }

  if (unit === "pie3") {
    return formatCubicFeet(value);
  }

  return formatCubicMeters(value);
}

function roundCurrencyValue(value: number) {
  return Math.round((Number.isFinite(value) ? value : 0) * 100) / 100;
}

function getProductArubaCategory(product: Pick<ProductOption, "arubaCategory" | "category"> | { arubaCategory?: string; category?: string }) {
  const arubaCategory = String(product.arubaCategory ?? "").trim();
  if (arubaCategory) {
    return arubaCategory;
  }
  return String(product.category ?? "").trim();
}

function mapRecordToProductOption(product: Record<string, unknown>): ProductOption {
  return {
    value: String(product._id ?? ""),
    label: String(product.name ?? ""),
    sku: String(product.sku ?? ""),
    category: String(product.category ?? ""),
    arubaCategory: String(product.arubaCategory ?? "").trim(),
    description: String(product.description ?? "").trim(),
    salePrice: roundCurrencyValue(Number(product.salePrice ?? 0)),
    inventoryAlert: Number(product.inventoryAlert ?? 0),
    productWeightKg: Number(product.productWeightKg ?? 0),
    exportVolumeCubicFeet: Number(product.exportVolumeCubicFeet ?? 0),
    displaysPerBox: Number(product.displaysPerBox ?? 1) || 1,
    arubaPurchaseCostUsd: Number(product.arubaPurchaseCostUsd ?? 0),
    arubaUsdToAwgRate: Number(product.arubaUsdToAwgRate ?? 1.79) || 1.79,
    presentation: String(product.presentation ?? "unidad"),
    containerType: String(product.containerType ?? "seco"),
    shareWithAruba: product.shareWithAruba !== false,
    variableSalePrice: Boolean(product.variableSalePrice),
    unitsPerBox: Number(product.unitsPerBox ?? 0),
    unitsPerBoxUnit: String(product.unitsPerBoxUnit ?? "unidad"),
    boxLengthCm: Number(product.boxLengthCm ?? 0),
    boxWidthCm: Number(product.boxWidthCm ?? 0),
    boxHeightCm: Number(product.boxHeightCm ?? 0),
  };
}

function formatProductDisplayInfo(product: {
  displaysPerBox?: number;
  unitsPerBox?: number;
  unitsPerBoxUnit?: string;
  productWeightKg?: number;
  exportVolumeCubicFeet?: number;
  containerType?: string;
}) {
  const parts: string[] = [];
  const displaysPerBox = Number(product.displaysPerBox ?? 1) || 1;
  const unitsPerBox = Number(product.unitsPerBox ?? 0);
  const productWeightKg = Number(product.productWeightKg ?? 0);
  const exportVolumeCubicFeet = getProductExportVolumeCubicFeet({
    containerType: product.containerType,
    exportVolumeCubicFeet: product.exportVolumeCubicFeet,
  });

  if (displaysPerBox > 1) {
    parts.push(`${displaysPerBox} displays/caja`);
  }

  if (unitsPerBox > 0) {
    parts.push(`${unitsPerBox} ${formatUnitsPerBoxUnitLabel(product.unitsPerBoxUnit ?? "unidad")}/und. export.`);
  }

  if (product.containerType === "refrigerado" && exportVolumeCubicFeet > 0) {
    parts.push(formatExportVolumeLabel(exportVolumeCubicFeet));
  } else if (productWeightKg > 0) {
    parts.push(formatExportWeightLabel(productWeightKg));
  }

  return parts.join(" · ");
}

function formatProductPackUnitsInfo(product: {
  displaysPerBox?: number;
  unitsPerBox?: number;
  unitsPerBoxUnit?: string;
}) {
  const parts: string[] = [];
  const displaysPerBox = Number(product.displaysPerBox ?? 1) || 1;
  const unitsPerBox = Number(product.unitsPerBox ?? 0);

  if (displaysPerBox > 1) {
    parts.push(`${displaysPerBox} displays/caja`);
  }

  if (unitsPerBox > 0) {
    parts.push(`${unitsPerBox} ${formatUnitsPerBoxUnitLabel(product.unitsPerBoxUnit ?? "unidad")}/und. export.`);
  }

  return parts.join(" · ");
}

function resolveProductInvoiceDescription(product: {
  description?: string;
  name?: string;
  label?: string;
  displaysPerBox?: number;
  unitsPerBox?: number;
  unitsPerBoxUnit?: string;
} | null | undefined) {
  const explicitDescription = String(product?.description ?? "").trim();

  if (explicitDescription) {
    return explicitDescription;
  }

  const packInfo = product ? formatProductPackUnitsInfo(product).trim() : "";

  if (packInfo) {
    return packInfo;
  }

  return "-";
}

function formatExportWeightLabel(weightKg: number) {
  if (!Number.isFinite(weightKg) || weightKg <= 0) {
    return "";
  }

  const normalized = Number(Number(weightKg).toFixed(3));
  return `${normalized} kg / und. exportación`;
}

function formatExportVolumeLabel(volumeCubicFeet: number) {
  if (!Number.isFinite(volumeCubicFeet) || volumeCubicFeet <= 0) {
    return "";
  }

  const normalized = Number(Number(volumeCubicFeet).toFixed(2));
  return `${normalized} pie3 / und. exportación`;
}

function buildInventoryEntryLotKey(
  productId: string,
  expirationDate: string,
  unitCostUsd = 0,
  salePriceAwg = 0,
) {
  return `${productId.trim()}::${expirationDate.trim() || "no-expiration"}::${roundCurrencyValue(unitCostUsd)}::${roundCurrencyValue(salePriceAwg)}`;
}

function buildDefaultInventoryLotName(expirationDate: string) {
  return expirationDate.trim() ? `Lote vence ${expirationDate.trim()}` : "Lote sin vencimiento";
}

function isCreationSectionKey(
  value: string,
): value is (typeof creationSectionKeys)[number] {
  return creationSectionKeys.includes(value as (typeof creationSectionKeys)[number]);
}

function getRoleLabel(role: string) {
  switch (role) {
    case "management":
      return "Gerencia";
    case "sales-rep-aruba":
      return "Vendedor Aruba";
    case "warehouse-aruba":
      return "Bodega Aruba";
    case "contabilidad":
      return "Contabilidad";
    case "colombia-ops":
      return "Operaciones Colombia";
    default:
      return "Acceso";
  }
}

function normalizeUppercaseInputTarget(target: EventTarget | null) {
  if (
    (target instanceof HTMLTextAreaElement || target instanceof HTMLInputElement) &&
    target.closest(".filter-grid")
  ) {
    return;
  }

  if (target instanceof HTMLTextAreaElement) {
    const uppercaseValue = target.value.toUpperCase();

    if (target.value !== uppercaseValue) {
      const selectionStart = target.selectionStart;
      const selectionEnd = target.selectionEnd;
      target.value = uppercaseValue;

      if (selectionStart !== null && selectionEnd !== null) {
        target.setSelectionRange(selectionStart, selectionEnd);
      }
    }

    return;
  }

  if (!(target instanceof HTMLInputElement)) {
    return;
  }

  if (!["text", "search", "email", "tel", "url"].includes(target.type)) {
    return;
  }

  const uppercaseValue = target.value.toUpperCase();

  if (target.value !== uppercaseValue) {
    const selectionStart = target.selectionStart;
    const selectionEnd = target.selectionEnd;
    target.value = uppercaseValue;

    if (selectionStart !== null && selectionEnd !== null) {
      target.setSelectionRange(selectionStart, selectionEnd);
    }
  }
}

