  async function handleRemoveProductFromSellerClient(storeId: string, productId: string) {
    if (!sessionUser || !isSellerOrderFlowActive) {
      return;
    }

    const salesRepId = resolveStaffOrderSalesRepId();

    if (!salesRepId) {
      setSellerProductOfferStatus({ tone: "error", message: "Selecciona una ruta con vendedor asignado." });
      return;
    }

    const storeOption = storeOptionsById.get(storeId);
    const currentAssignedProductIds = storeOption?.assignedProductIds
      ?? sellerClientProducts.map((product) => product.productId);
    const nextAssignedProductIds = currentAssignedProductIds.filter((entry) => entry !== productId);

    if (nextAssignedProductIds.length === currentAssignedProductIds.length) {
      return;
    }

    try {
      setRemovingSellerProductId(productId);
      setSellerProductOfferStatus(null);
      const response = await fetch(`${apiBaseUrl}/sales/stores/${storeId}/assigned-products`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          salesRepId,
          assignedProductIds: nextAssignedProductIds,
        }),
      });
      const data = (await response.json()) as {
        message?: string;
        store?: { assignedProductIds?: string[] };
      };

      if (!response.ok) {
        setSellerProductOfferStatus({ tone: "error", message: data.message ?? "No fue posible quitar el producto del cliente." });
        return;
      }

      const assignedProductIds = Array.isArray(data.store?.assignedProductIds)
        ? data.store.assignedProductIds.map((entry) => String(entry)).filter(Boolean)
        : nextAssignedProductIds;

      setStoreOptions((current) => current.map((store) => (
        store.value === storeId
          ? { ...store, assignedProductIds }
          : store
      )));

      setSellerClientProducts((current) => current.filter((product) => product.productId !== productId));
      setSellerOrderDraft((current) => {
        if (!(productId in current)) {
          return current;
        }

        const next = { ...current };
        delete next[productId];
        return next;
      });

      setSellerProductOfferStatus({ tone: "success", message: data.message ?? "Producto quitado del cliente." });
      void refreshSellerProductCatalog(storeId);
    } catch {
      setSellerProductOfferStatus({ tone: "error", message: "No fue posible conectar con el backend." });
    } finally {
      setRemovingSellerProductId("");
    }
  }

  function renderSellerAssignedProductRow(product: SellerClientProduct, storeId: string, showOrderFields: boolean) {
    const draft = sellerOrderDraft[product.productId] ?? { stockCurrent: "", quantity: "", notes: "" };
    const quantityValue = Number(draft.quantity || 0);
    const lineTotal = Number.isFinite(quantityValue) && quantityValue > 0
      ? roundCurrencyValue(Number(product.promotion?.promotionSalePrice ?? product.salePrice ?? 0) * quantityValue)
      : 0;
    const catalogMatch = [...sellerProductCatalog.expiringSoon, ...sellerProductCatalog.products]
      .find((entry) => entry.productId === product.productId);
    const warehouseStock = Number(product.warehouseStock ?? catalogMatch?.warehouseStock ?? 0);

    const isRemoving = removingSellerProductId === product.productId;

    return (
      <article className="seller-product-catalog-row seller-product-catalog-row-assigned" key={`seller-assigned-${product.productId}`}>
        <div className="seller-product-catalog-product">
          {product.imageUrl ? (
            <img className="seller-product-thumb" src={product.imageUrl} alt={product.name} />
          ) : (
            <div className="seller-product-thumb seller-product-thumb-placeholder">SIN IMAGEN</div>
          )}
          <div className="seller-product-catalog-product-copy">
            <div className="seller-product-catalog-product-title">
              <strong>{product.name}</strong>
              <button
                className="seller-assigned-product-remove"
                type="button"
                aria-label={`Quitar ${product.name}`}
                title="Quitar producto del cliente"
                disabled={isRemoving}
                onClick={() => void handleRemoveProductFromSellerClient(storeId, product.productId)}
              >
                {isRemoving ? "..." : "×"}
              </button>
            </div>
            <small>SKU {product.sku}{getProductArubaCategory(product) ? ` · ${getProductArubaCategory(product)}` : ""}</small>
          </div>
        </div>
        <div className="seller-product-catalog-meta">
          {renderPromotionPrice(product)}
          <strong>Stock bodega: {warehouseStock} uds.</strong>
          {formatProductDisplayInfo(product) ? (
            <small>{formatProductDisplayInfo(product)}</small>
          ) : null}
        </div>
        <div className="seller-product-catalog-order-fields">
          <label className="seller-product-catalog-field seller-product-catalog-field-quantity">
            <span>Cantidad (displays)</span>
            <div className="seller-quantity-stepper">
              <button
                className="seller-quantity-stepper-btn"
                type="button"
                aria-label="Disminuir cantidad"
                disabled={!Number.isFinite(quantityValue) || quantityValue <= 0}
                onClick={() => adjustSellerOrderQuantity(product.productId, -1)}
              >
                −
              </button>
            <input
              className="catalog-price-input seller-order-input"
              type="number"
              min="0"
              step="any"
              value={draft.quantity}
              placeholder="0"
              onChange={(event) => handleSellerOrderDraftChange(product.productId, "quantity", event.target.value)}
            />
              <button
                className="seller-quantity-stepper-btn"
                type="button"
                aria-label="Aumentar cantidad"
                onClick={() => adjustSellerOrderQuantity(product.productId, 1)}
              >
                +
              </button>
            </div>
          </label>
          {showOrderFields && Number.isFinite(quantityValue) && quantityValue > 0 ? (
            <div className="seller-product-catalog-field seller-product-catalog-field-total">
              <span>Subtotal</span>
              <strong>{formatAwgCurrency(lineTotal)} AWG</strong>
            </div>
          ) : null}
          {showOrderFields ? (
            <label className="seller-product-catalog-field seller-product-catalog-field-notes">
              <span>Notas</span>
              <input
                className="seller-order-note-input"
                type="text"
                value={draft.notes}
                placeholder="Observación para bodega"
                onChange={(event) => handleSellerOrderDraftChange(product.productId, "notes", event.target.value)}
              />
            </label>
          ) : null}
        </div>
      </article>
    );
  }

