  function renderSellerProductCatalogPanel(storeId: string | null, options?: { showOrderFields?: boolean }) {
    if (!storeId) {
      return null;
    }

    const storeOption = storeOptionsById.get(storeId);
    const assignedCount = storeOption?.assignedProductIds.length ?? 0;
    const showOrderFields = options?.showOrderFields ?? false;
    const assignedProducts = sellerAssignedStore?.id === storeId ? sellerClientProducts : [];
    const filteredExpiringSoon = sellerProductCatalog.expiringSoon.filter((product) => (
      !product.isAssigned
    ));
    const filteredProducts = sellerProductCatalog.products.filter((product) => (
      !product.isAssigned && matchesSellerCatalogSearch(product, sellerCatalogSearchQuery)
    ));
    const totalCatalogPages = Math.max(1, Math.ceil(filteredProducts.length / sellerCatalogPageSize));
    const currentCatalogPage = Math.min(sellerCatalogPage, totalCatalogPages);
    const catalogPageStart = (currentCatalogPage - 1) * sellerCatalogPageSize;
    const paginatedProducts = filteredProducts.slice(catalogPageStart, catalogPageStart + sellerCatalogPageSize);
    const catalogPageNumbers = Array.from({ length: totalCatalogPages }, (_, index) => index + 1);

    return (
      <article className="seller-product-catalog">
        <div className="client-product-assignment-header">
          <div>
            <p className="section-label">Ofrecer productos</p>
            <h3>Catalogo de bodega</h3>
            <p>Agrega productos nuevos al cliente. Prioriza los que estan proximos a vencer.</p>
          </div>
          <span>{assignedCount} producto{assignedCount === 1 ? "" : "s"} asignados</span>
        </div>

        {sellerProductOfferStatus ? <p className={`form-feedback ${sellerProductOfferStatus.tone}`}>{sellerProductOfferStatus.message}</p> : null}
        {sellerProductCatalogError ? <p className="form-feedback error">{sellerProductCatalogError}</p> : null}

        {sellerClientProductsError ? <p className="form-feedback error">{sellerClientProductsError}</p> : null}
        {showOrderFields && sellerOrderStatus ? <p className={`form-feedback ${sellerOrderStatus.tone}`}>{sellerOrderStatus.message}</p> : null}

        <section className="seller-product-catalog-section seller-product-catalog-section-assigned">
          <div className="seller-product-catalog-section-header">
            <p className="section-label">Cliente</p>
            <h4>Productos asignados a este cliente</h4>
            <p className="seller-product-catalog-count">
              {assignedProducts.length > 0
                ? `${assignedProducts.length} producto${assignedProducts.length === 1 ? "" : "s"} listos para registrar cantidades.`
                : "Agrega productos desde el catalogo de abajo."}
            </p>
          </div>
          {isLoadingSellerClientProducts ? (
            <p className="route-empty-state">Cargando productos asignados...</p>
          ) : assignedProducts.length > 0 ? (
              <div className="seller-product-catalog-list">
                {assignedProducts.map((product) => renderSellerAssignedProductRow(product, storeId, showOrderFields))}
              </div>
          ) : (
            <p className="route-empty-state">Este cliente aun no tiene productos asignados.</p>
          )}
        </section>

        {isLoadingSellerProductCatalog ? (
          <p className="route-empty-state">Cargando catalogo de bodega...</p>
        ) : (
          <>
            <section className="seller-product-catalog-section">
              <div className="seller-product-catalog-section-header">
                <p className="section-label">Prioridad</p>
                <h4>Proximos a vencer</h4>
              </div>
              {filteredExpiringSoon.length > 0 ? (
                <div className="seller-product-catalog-list">
                  {filteredExpiringSoon.map((product) => renderSellerCatalogProductRow(product, storeId))}
                </div>
              ) : (
                <p className="route-empty-state">
                  No hay productos proximos a vencer con stock en bodega.
                </p>
              )}
            </section>

            <section className="seller-product-catalog-section">
              <div className="seller-product-catalog-section-header">
                <p className="section-label">Catalogo</p>
                <h4>Todos los productos</h4>
                {filteredProducts.length > 0 ? (
                  <p className="seller-product-catalog-count">
                    Mostrando {catalogPageStart + 1}-{Math.min(catalogPageStart + sellerCatalogPageSize, filteredProducts.length)} de {filteredProducts.length}
                  </p>
                ) : sellerCatalogSearchQuery.trim() ? (
                  <p className="seller-product-catalog-count">0 productos encontrados</p>
                ) : null}
              </div>
              <div className="seller-product-catalog-filters">
                <label className="field field-full">
                  <span>Buscar producto</span>
                  <input
                    type="search"
                    value={sellerCatalogSearchQuery}
                    placeholder="Nombre, SKU o categoria"
                    onChange={(event) => setSellerCatalogSearchQuery(event.target.value)}
                  />
                </label>
              </div>
              {paginatedProducts.length > 0 ? (
                <>
                  <div className="seller-product-catalog-list">
                    {paginatedProducts.map((product) => renderSellerCatalogProductRow(product, storeId))}
                  </div>
                  {filteredProducts.length > sellerCatalogPageSize ? (
                    <div className="seller-catalog-pagination">
                      <button
                        className="seller-catalog-pagination-button"
                        type="button"
                        disabled={currentCatalogPage <= 1}
                        onClick={() => setSellerCatalogPage((current) => Math.max(1, current - 1))}
                      >
                        ‹
                      </button>
                      {catalogPageNumbers.map((pageNumber) => (
                        <button
                          key={`seller-catalog-page-${pageNumber}`}
                          className={`seller-catalog-pagination-button ${pageNumber === currentCatalogPage ? "is-active" : ""}`}
                          type="button"
                          onClick={() => setSellerCatalogPage(pageNumber)}
                        >
                          {pageNumber}
                        </button>
                      ))}
                      <button
                        className="seller-catalog-pagination-button"
                        type="button"
                        disabled={currentCatalogPage >= totalCatalogPages}
                        onClick={() => setSellerCatalogPage((current) => Math.min(totalCatalogPages, current + 1))}
                      >
                        ›
                      </button>
                    </div>
                  ) : null}
                </>
              ) : (
                <p className="route-empty-state">
                  {sellerCatalogSearchQuery.trim()
                    ? "No hay productos que coincidan con la busqueda."
                    : "No hay mas productos disponibles fuera de la seccion de vencimiento."}
                </p>
              )}
            </section>
          </>
        )}
      </article>
    );
  }

  async function refreshReferenceOptions() {
    try {
      const readReferenceCollection = (path: string) => fetch(`${apiBaseUrl}${path}`).then(async (response) => ({
        response,
        data: (await response.json()) as Array<Record<string, unknown>> | { message?: string },
      }));

      const [categoryResult, supplierResult, usersResult, clientsResult, operationsClientsResult, warehousesResult, productsResult] = await Promise.allSettled([
        readReferenceCollection("/management/categories"),
        readReferenceCollection("/management/suppliers"),
        readReferenceCollection("/management/users"),
        readReferenceCollection("/management/clients"),
        readReferenceCollection("/management/ops-clients"),
        readReferenceCollection("/management/warehouses"),
        readReferenceCollection("/management/products"),
      ]);

      if (categoryResult.status === "fulfilled" && categoryResult.value.response.ok && Array.isArray(categoryResult.value.data)) {
        setCategoryOptions(
          categoryResult.value.data
            .map((category) => ({
              value: String(category.name ?? ""),
              label: String(category.name ?? ""),
              market: String(category.market ?? "colombia") === "aruba" ? "aruba" as const : "colombia" as const,
            }))
            .filter((category) => category.value.length > 0),
        );
      }

      if (supplierResult.status === "fulfilled" && supplierResult.value.response.ok && Array.isArray(supplierResult.value.data)) {
        setSupplierOptions(
          supplierResult.value.data
            .map((supplier) => ({ value: String(supplier.name ?? ""), label: String(supplier.name ?? "") }))
            .filter((supplier) => supplier.value.length > 0),
        );
      }

      if (usersResult.status === "fulfilled" && usersResult.value.response.ok && Array.isArray(usersResult.value.data)) {
        const nextSalesReps = usersResult.value.data
          .filter((user) => user.role === "sales-rep-aruba" && user.active !== false)
          .map((user) => ({
            value: String(user._id ?? ""),
            label: String(user.name ?? user.email ?? "Vendedor sin nombre"),
          }))
          .filter((user) => user.value.length > 0);

        setSalesRepOptions(nextSalesReps);
        setRouteForm((current) => ({
          ...current,
          salesRepId: current.salesRepId || nextSalesReps[0]?.value || "",
        }));
      }

      if (clientsResult.status === "fulfilled" && clientsResult.value.response.ok && Array.isArray(clientsResult.value.data)) {
        setStoreOptions(
          clientsResult.value.data
            .map((client) => ({
              value: String(client._id ?? ""),
              label: String(client.name ?? ""),
              address: String(client.address ?? ""),
              code: String(client.code ?? ""),
              email: String(client.email ?? ""),
              phone: String(client.phone ?? ""),
              managerName: String(client.managerName ?? ""),
              defaultPaymentMethod: normalizeClientPaymentTerms(
                typeof client.defaultPaymentMethod === "string" ? client.defaultPaymentMethod : "",
              ),
              assignedProductIds: Array.isArray(client.assignedProductIds)
                ? client.assignedProductIds.map((entry) => String(entry)).filter(Boolean)
                : [],
            }))
            .filter((client) => client.value.length > 0 && client.label.length > 0),
        );
      }

      if (operationsClientsResult.status === "fulfilled" && operationsClientsResult.value.response.ok && Array.isArray(operationsClientsResult.value.data)) {
        setOperationsClientOptions(
          operationsClientsResult.value.data
            .map((client) => mapOperationsClientOption(client))
            .filter((client) => client.value.length > 0 && client.label.length > 0),
        );
      }

      if (warehousesResult.status === "fulfilled" && warehousesResult.value.response.ok && Array.isArray(warehousesResult.value.data)) {
        const nextWarehouseOptions = warehousesResult.value.data
          .filter((warehouse) => warehouse.active !== false)
          .map((warehouse) => ({
            value: String(warehouse._id ?? ""),
            label: String(warehouse.name ?? ""),
            code: String(warehouse.code ?? ""),
            address: String(warehouse.address ?? ""),
          }))
          .filter((warehouse) => warehouse.value.length > 0 && warehouse.label.length > 0);

        setWarehouseOptions(nextWarehouseOptions);
        setSelectedWarehouseId((current) => current || nextWarehouseOptions[0]?.value || "");
      }

      if (productsResult.status === "fulfilled" && productsResult.value.response.ok && Array.isArray(productsResult.value.data)) {
        const nextProductOptions = productsResult.value.data
          .filter((product) => isProductVisibleForSession(product, sessionUser))
          .filter((product) => product.active !== false)
          .map((product) => mapRecordToProductOption(product))
          .filter((product) => product.value.length > 0 && product.label.length > 0);

        setProductOptions(nextProductOptions);
        setWarehouseLocationForm((current) => ({
          ...current,
          productId: current.productId || nextProductOptions[0]?.value || "",
        }));
      }
    } catch {
      return;
    }
  }

  async function refreshCreationRows(config: CollectionConfig, options?: { silent?: boolean }) {
    try {
      if (!options?.silent) {
        setIsLoadingCreationRows(true);
      }
      setCreationRowsError("");
      const response = await fetch(`${apiBaseUrl}${config.endpoint}`);
      const data = (await response.json()) as Array<Record<string, unknown>> | { message?: string };

      if (!response.ok || !Array.isArray(data)) {
        setCreationRowsError(Array.isArray(data) ? "No fue posible cargar los registros." : data.message ?? "No fue posible cargar los registros.");
        return null;
      }

      setDatabaseRows((current) => ({
        ...current,
        [config.key]: data,
      }));

      return data;
    } catch {
      setCreationRowsError("No fue posible conectar con el backend.");
      return null;
    } finally {
      if (!options?.silent) {
        setIsLoadingCreationRows(false);
      }
    }
  }

