  async function refreshLogisticsAccountingData() {
    try {
      setIsLoadingLogisticsAccounting(true);
      setLogisticsAccountingError("");
      const [invoicesRes, billedOrdersRes, fixedRes, expensesRes] = await Promise.all([
        fetch(`${apiBaseUrl}/management/logistics-accounting/invoices`),
        fetch(`${apiBaseUrl}/management/logistics-accounting/billed-orders`),
        fetch(`${apiBaseUrl}/management/logistics-accounting/fixed-costs`),
        fetch(`${apiBaseUrl}/management/logistics-accounting/expenses`),
      ]);
      const invoicesData = (await invoicesRes.json()) as LogisticsInvoiceRecord[] | { message?: string };
      const billedOrdersPayload = billedOrdersRes.ok
        ? ((await billedOrdersRes.json()) as LogisticsBilledOrderRecord[] | { message?: string })
        : [];
      const fixedData = (await fixedRes.json()) as LogisticsFixedCostRecord[] | { message?: string };
      const expensesData = (await expensesRes.json()) as LogisticsExpenseRecord[] | { message?: string };

      if (
        !invoicesRes.ok || !Array.isArray(invoicesData)
        || !fixedRes.ok || !Array.isArray(fixedData)
        || !expensesRes.ok || !Array.isArray(expensesData)
      ) {
        setLogisticsAccountingError("No fue posible cargar la informacion contable logistica.");
        return;
      }

      const billedOrdersData = Array.isArray(billedOrdersPayload)
        ? billedOrdersPayload
        : invoicesData
            .filter((invoice) => typeof invoice.orderId === "string" && invoice.orderId.trim().length > 0)
            .map((invoice) => ({
              _id: invoice._id,
              orderId: String(invoice.orderId ?? ""),
              invoiceDate: invoice.invoiceDate,
              storeName: invoice.storeName,
              salesRepName: invoice.salesRepName,
              routeName: invoice.routeName,
              totalCostAwg: Number(invoice.totalCostAwg ?? 0),
              totalRevenueAwg: Number(invoice.totalRevenueAwg ?? 0),
              totalUtilityAwg: Number(invoice.totalUtilityAwg ?? 0),
            }));

      setLogisticsInvoices(invoicesData);
      setLogisticsBilledOrders(billedOrdersData);
      setLogisticsFixedCosts(fixedData);
      setLogisticsExpenses(expensesData);
    } catch {
      setLogisticsAccountingError("No fue posible conectar con el backend.");
    } finally {
      setIsLoadingLogisticsAccounting(false);
    }
  }

  async function refreshCarteraData(options?: {
    startDate?: string;
    endDate?: string;
    collectionStartDate?: string;
    collectionEndDate?: string;
    collectionPaymentMethod?: CarteraCollectionPaymentMethod | "";
    unfiltered?: boolean;
  }) {
    try {
      setIsLoadingCartera(true);
      setCarteraError("");

      const params = new URLSearchParams();

      if (!options?.unfiltered) {
        const normalizedRange = normalizeCarteraDateRange(
          options?.startDate ?? carteraStartDateFilter,
          options?.endDate ?? carteraEndDateFilter,
        );
        const normalizedCollectionRange = normalizeCarteraDateRange(
          options?.collectionStartDate ?? carteraCollectionStartDateFilter,
          options?.collectionEndDate ?? carteraCollectionEndDateFilter,
        );
        const collectionPaymentMethod = options?.collectionPaymentMethod ?? carteraCollectionPaymentMethodFilter;

        if (normalizedRange.startDate) {
          params.set("startDate", normalizedRange.startDate);
        }

        if (normalizedRange.endDate) {
          params.set("endDate", normalizedRange.endDate);
        }

        if (normalizedCollectionRange.startDate) {
          params.set("collectionStartDate", normalizedCollectionRange.startDate);
        }

        if (normalizedCollectionRange.endDate) {
          params.set("collectionEndDate", normalizedCollectionRange.endDate);
        }

        if (collectionPaymentMethod) {
          params.set("collectionPaymentMethod", collectionPaymentMethod);
        }
      }

      const query = params.toString().length > 0 ? `?${params.toString()}` : "";
      const response = await fetch(`${apiBaseUrl}/management/cartera${query}`);
      const data = (await response.json()) as {
        summary?: CarteraSummary;
        entries?: CarteraEntryRecord[];
        overdueEntries?: CarteraEntryRecord[];
        collections?: CarteraCollectionRecord[];
        message?: string;
      };

      if (!response.ok || !Array.isArray(data.entries) || !Array.isArray(data.collections) || !data.summary) {
        setCarteraError(data.message ?? "No fue posible cargar la cartera.");
        return;
      }

      setCarteraRows(data.entries);
      setCarteraOverdueRows(Array.isArray(data.overdueEntries) ? data.overdueEntries : []);
      setCarteraCollections(data.collections);
      setCarteraSummary(data.summary);
    } catch {
      setCarteraError("No fue posible conectar con el backend.");
    } finally {
      setIsLoadingCartera(false);
    }
  }

  async function refreshFinancialReports() {
    try {
      setIsLoadingFinancialReports(true);
      setFinancialReportsError("");

      const normalizedRange = normalizeCarteraDateRange(financialReportsStartDate, financialReportsEndDate);
      const params = new URLSearchParams();

      if (normalizedRange.startDate) {
        params.set("startDate", normalizedRange.startDate);
      }

      if (normalizedRange.endDate) {
        params.set("endDate", normalizedRange.endDate);
      }

      if (financialReportsStoreId) {
        params.set("storeId", financialReportsStoreId);
      }

      const query = params.toString().length > 0 ? `?${params.toString()}` : "";
      const response = await fetch(`${apiBaseUrl}/management/financial-reports${query}`);
      const data = (await response.json()) as FinancialReportsData & { message?: string };

      if (!response.ok || !data.profitAndLoss || !data.balance) {
        setFinancialReportsError(data.message ?? "No fue posible cargar los reportes financieros.");
        return;
      }

      setFinancialReportsData(data);
    } catch {
      setFinancialReportsError("No fue posible conectar con el backend.");
    } finally {
      setIsLoadingFinancialReports(false);
    }
  }

  async function refreshOrderPlanner() {
    try {
      setIsLoadingOrderPlanner(true);
      setOrderPlannerError("");

      const normalizedRange = normalizeCarteraDateRange(orderPlannerStartDate, orderPlannerEndDate);
      const params = new URLSearchParams();
      const coverageDays = Math.min(90, Math.max(1, Math.round(Number(orderPlannerCoverageDays) || 14)));

      if (normalizedRange.startDate) {
        params.set("startDate", normalizedRange.startDate);
      }

      if (normalizedRange.endDate) {
        params.set("endDate", normalizedRange.endDate);
      }

      params.set("coverageDays", String(coverageDays));

      if (orderPlannerCategoryFilter) {
        params.set("category", orderPlannerCategoryFilter);
      }

      if (selectedOrderPlannerProductId) {
        params.set("productId", selectedOrderPlannerProductId);
      }

      if (orderPlannerAlertsOnly) {
        params.set("alertsOnly", "true");
      }

      const response = await fetch(`${apiBaseUrl}/management/order-planner?${params.toString()}`);
      const data = (await response.json()) as OrderPlannerData & { message?: string };

      if (!response.ok || !Array.isArray(data.products) || !data.summary) {
        setOrderPlannerError(data.message ?? "No fue posible cargar el planificador de pedidos.");
        return;
      }

      setOrderPlannerData(data);
    } catch {
      setOrderPlannerError("No fue posible conectar con el backend.");
    } finally {
      setIsLoadingOrderPlanner(false);
    }
  }

  function openCarteraCollectForm(entry: CarteraEntryRecord) {
    if (!entry._id) {
      return;
    }

    setCarteraCollectEntryId(entry._id);
    setCarteraCollectionDraft({
      amountAwg: String(entry.outstandingAmountAwg ?? 0),
      paymentMethod: "",
      collectedAt: new Date().toISOString().slice(0, 10),
    });
    setCarteraCollectionStatus(null);
  }

  async function handleRegisterCarteraCollection(entry: CarteraEntryRecord) {
    if (!entry._id) {
      return;
    }

    const amountAwg = Number(carteraCollectionDraft.amountAwg || 0);
    const outstandingAmountAwg = Number(entry.outstandingAmountAwg ?? 0);

    if (amountAwg <= 0) {
      setCarteraCollectionStatus({ tone: "error", message: "Indica un monto de recaudo valido." });
      return;
    }

    if (!carteraCollectionDraft.paymentMethod) {
      setCarteraCollectionStatus({ tone: "error", message: "Selecciona un metodo de recaudo." });
      return;
    }

    if (amountAwg > outstandingAmountAwg + 0.009) {
      setCarteraCollectionStatus({ tone: "error", message: "El monto supera el saldo pendiente de la factura." });
      return;
    }

    try {
      setIsSavingCarteraCollection(true);
      setCarteraCollectionStatus(null);

      const response = await fetch(`${apiBaseUrl}/management/cartera/entries/${entry._id}/collect`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          amountAwg,
          paymentMethod: carteraCollectionDraft.paymentMethod,
          collectedAt: carteraCollectionDraft.collectedAt,
        }),
      });
      const data = (await response.json()) as { message?: string };

      if (!response.ok) {
        throw new Error(data.message ?? "No fue posible registrar el recaudo.");
      }

      setCarteraCollectEntryId("");
      setCarteraCollectionDraft({
        amountAwg: "",
        paymentMethod: "",
        collectedAt: new Date().toISOString().slice(0, 10),
      });
      setCarteraCollectionStatus({ tone: "success", message: data.message ?? "Recaudo registrado correctamente." });
      await refreshCarteraData();
    } catch (error) {
      setCarteraCollectionStatus({
        tone: "error",
        message: error instanceof Error ? error.message : "No fue posible registrar el recaudo.",
      });
    } finally {
      setIsSavingCarteraCollection(false);
    }
  }

  async function refreshWarehousePendingCredit(storeId: string) {
    if (!storeId.trim()) {
      setWarehousePendingCreditEntries([]);
      setWarehouseCreditCollectionDrafts({});
      return;
    }

    try {
      setIsLoadingWarehousePendingCredit(true);
      setWarehousePendingCreditError("");
      const response = await fetch(`${apiBaseUrl}/warehouse/cartera/pending-credit?storeId=${encodeURIComponent(storeId)}`);
      const data = (await response.json()) as CarteraEntryRecord[] | { message?: string };

      if (!response.ok || !Array.isArray(data)) {
        throw new Error("message" in data ? data.message ?? "No fue posible cargar el credito pendiente." : "No fue posible cargar el credito pendiente.");
      }

      setWarehousePendingCreditEntries(data);
      setWarehouseCreditCollectionDrafts(
        data.reduce<Record<string, WarehouseCreditCollectionDraft>>((drafts, entry) => {
          if (!entry._id) {
            return drafts;
          }

          drafts[entry._id] = {
            carteraEntryId: entry._id,
            amountAwg: String(entry.outstandingAmountAwg ?? 0),
            paymentMethod: "",
            selected: false,
          };
          return drafts;
        }, {}),
      );
    } catch (error) {
      setWarehousePendingCreditEntries([]);
      setWarehouseCreditCollectionDrafts({});
      setWarehousePendingCreditError(error instanceof Error ? error.message : "No fue posible cargar el credito pendiente.");
    } finally {
      setIsLoadingWarehousePendingCredit(false);
    }
  }

  async function refreshInventorySummary() {
    try {
      setIsLoadingInventory(true);
      setInventoryError("");
      const arubaInventoryRoles = new Set(["warehouse-aruba", "sales-rep-aruba", "management", "contabilidad"]);
      const businessUnit = arubaInventoryRoles.has(String(sessionUser?.role ?? "")) ? "aruba" : "colombia";
      const response = await fetch(`${apiBaseUrl}/management/inventory-summary?businessUnit=${businessUnit}`);
      const data = (await response.json()) as InventorySummaryResponse | { message?: string };

      if (!response.ok || !("rows" in data) || !Array.isArray(data.rows)) {
        setInventoryError("message" in data ? data.message ?? "No fue posible cargar el inventario." : "No fue posible cargar el inventario.");
        return;
      }

      setInventoryRows(data.rows);
      setInventoryKpis(data.kpis);
      setInventoryHistoryRows(Array.isArray(data.history) ? data.history : []);
    } catch {
      setInventoryError("No fue posible conectar con el backend.");
    } finally {
      setIsLoadingInventory(false);
    }
  }

