  async function saveCurrentImportFormAsTemplate() {
    if (!sessionUser) {
      setAccountingStatuses({
        importCosts: { tone: "error", message: "Debes estar logueado para guardar plantillas." },
      });
      return "";
    }

    const fallbackName = `Plantilla ${formatContainerType(containerImportForm.containerType)} ${formatContainerSize(containerImportForm.containerSize)} ${containerImportForm.measurementUnit.toUpperCase()}`;
    const nextTemplateName = importTemplateName.trim() || fallbackName;
    const normalizedName = nextTemplateName.toLowerCase();

    const existingTemplate = importContainerTemplates.find(
      (template) => template.name.trim().toLowerCase() === normalizedName,
    );

    const templatePayload = {
      userId: sessionUser.id,
      name: nextTemplateName,
      containerType: containerImportForm.containerType,
      containerSize: containerImportForm.containerSize,
      measurementUnit: containerImportForm.measurementUnit,
      notes: containerImportForm.notes,
      expenseItems: containerImportForm.expenseItems.map((expense) => ({
        key: expense.key,
        label: expense.label,
        amount: Number(expense.amount || 0),
        documents: expense.documents,
      })),
      products: containerImportForm.products.map((product) => ({ ...product })),
    };

    try {
      let result: ImportContainerTemplateRecord;

      if (existingTemplate) {
        const response = await fetch(`${apiBaseUrl}/management/import-templates/${getTemplateId(existingTemplate)}`, {
          method: "PUT",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(templatePayload),
        });

        if (!response.ok) {
          throw new Error("No fue posible actualizar la plantilla.");
        }

        result = (await response.json()) as ImportContainerTemplateRecord;
      } else {
        const response = await fetch(`${apiBaseUrl}/management/import-templates`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(templatePayload),
        });

        if (!response.ok) {
          throw new Error("No fue posible guardar la plantilla.");
        }

        result = (await response.json()) as ImportContainerTemplateRecord;
      }

      setImportContainerTemplates((current) =>
        existingTemplate
          ? current.map((template) => (getTemplateId(template) === getTemplateId(existingTemplate) ? result : template))
          : [result, ...current],
      );

      return result.name;
    } catch (error) {
      setAccountingStatuses({
        importCosts: {
          tone: "error",
          message: error instanceof Error ? error.message : "Error al guardar la plantilla.",
        },
      });
      return "";
    }
  }

  async function applySelectedImportTemplate(templateId: string) {
    const selectedTemplate = importContainerTemplates.find((template) => String(template._id ?? template.id) === templateId);

    if (!selectedTemplate) {
      return;
    }

    const productsById = new Map(selectedTemplate.products.map((product) => [product.productId, product]));

    setContainerImportForm((current) => ({
      ...current,
      containerType: selectedTemplate.containerType,
      containerSize: selectedTemplate.containerSize,
      measurementUnit: selectedTemplate.measurementUnit,
      notes: selectedTemplate.notes,
      expenseItems: selectedTemplate.expenseItems.map((expense) =>
        createImportExpenseItem(expense.key, {
          label: expense.label,
          amount: String(expense.amount),
          documents: expense.documents,
        }),
      ),
      products: buildContainerImportProducts(productOptions).map((product) => {
        const templateProduct = productsById.get(product.productId);

        if (!templateProduct) {
          return product;
        }

        return {
          ...product,
          selected: templateProduct.selected,
          boxCount:
            String(templateProduct.boxCount ?? "").trim()
            || String(
              deriveExportUnitCountFromImportedQuantity(
                Number(templateProduct.importedQuantity ?? 0),
                Number(productOptions.find((option) => option.value === product.productId)?.unitsPerBox ?? 0),
              ),
            ),
          importedQuantity: templateProduct.importedQuantity,
          purchaseUnitCostOrigin: templateProduct.purchaseUnitCostOrigin,
          purchaseBoxCostOrigin: templateProduct.purchaseBoxCostOrigin,
          expirationDate: templateProduct.expirationDate ?? "",
        };
      }),
    }));

    setAccountingStatuses((current) => ({
      ...current,
      importCosts: { tone: "success", message: `Plantilla ${selectedTemplate.name} aplicada.` },
    }));
  }

